import{_ as d}from"./chunks/editor-overview.BjX_DzOe.js";import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.CvgP6Fyv.js";const l="/screenshots/rubber-band.png",i="/screenshots/group-move.png",c="/screenshots/create-drag.png",h="/screenshots/create-popover.png",f=JSON.parse('{"title":"クラスターエディタ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cluster-editor.md","filePath":"guide/cluster-editor.md"}'),s={name:"guide/cluster-editor.md"};function n(p,t,b,u,m,g){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="クラスターエディタ" tabindex="-1">クラスターエディタ <a class="header-anchor" href="#クラスターエディタ" aria-label="Permalink to &quot;クラスターエディタ&quot;">​</a></h1><p>クラスターエディタは、AI が検出した入力項目（クラスター）を視覚的に編集するための画面です。<strong>選択モード</strong> と <strong>作成モード</strong> の2つのモードがあります。</p><p><img src="'+d+'" alt="クラスターエディタ全体"></p><hr><h2 id="モード切替" tabindex="-1">モード切替 <a class="header-anchor" href="#モード切替" aria-label="Permalink to &quot;モード切替&quot;">​</a></h2><p>ツールバー左端のボタン、またはキーボードショートカットでモードを切り替えます。</p><table tabindex="0"><thead><tr><th>モード</th><th>ボタン</th><th>ショートカット</th><th>用途</th></tr></thead><tbody><tr><td>選択</td><td>矢印アイコン</td><td><code>V</code></td><td>クラスターの選択・移動・リサイズ</td></tr><tr><td>作成</td><td>＋アイコン</td><td><code>N</code></td><td>新規クラスターの追加</td></tr></tbody></table><p><code>Esc</code> キーでいつでも選択モードに戻れます。</p><hr><h2 id="選択モード" tabindex="-1">選択モード <a class="header-anchor" href="#選択モード" aria-label="Permalink to &quot;選択モード&quot;">​</a></h2><h3 id="単一選択" tabindex="-1">単一選択 <a class="header-anchor" href="#単一選択" aria-label="Permalink to &quot;単一選択&quot;">​</a></h3><p>クラスターをクリックすると選択されます。選択中のクラスターは青い枠線で強調表示され、右側のプロパティパネルに詳細が表示されます。</p><h3 id="複数選択" tabindex="-1">複数選択 <a class="header-anchor" href="#複数選択" aria-label="Permalink to &quot;複数選択&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td>個別追加/除外</td><td><code>Shift</code> または <code>Ctrl</code>/<code>Cmd</code> + クリック</td></tr><tr><td>範囲選択</td><td>背景をドラッグして矩形で囲む（ラバーバンド選択）</td></tr><tr><td>全選択</td><td>ツールバーの「全選択」ボタン</td></tr><tr><td>選択解除</td><td>背景をクリック、またはツールバーの「選択解除」</td></tr></tbody></table><p><img src="'+l+'" alt="ラバーバンド選択"></p><h3 id="移動" tabindex="-1">移動 <a class="header-anchor" href="#移動" aria-label="Permalink to &quot;移動&quot;">​</a></h3><p><strong>ドラッグ移動:</strong></p><ul><li>単一選択: クラスター内部をドラッグ</li><li>複数選択: バウンディングボックス（破線の囲み枠）をドラッグすると全選択クラスターが一緒に移動</li></ul><p><img src="'+i+'" alt="グループ移動"></p><p><strong>キーボードナッジ:</strong></p><table tabindex="0"><thead><tr><th>キー</th><th>移動量</th></tr></thead><tbody><tr><td><code>↑</code> <code>↓</code> <code>←</code> <code>→</code></td><td>1px</td></tr><tr><td><code>Shift</code> + 矢印</td><td>10px</td></tr></tbody></table><p>ツールバーのナッジボタン（十字矢印）でも同様の操作が可能です。</p><h3 id="リサイズ" tabindex="-1">リサイズ <a class="header-anchor" href="#リサイズ" aria-label="Permalink to &quot;リサイズ&quot;">​</a></h3><p>単一選択時に表示される 8 つのハンドル（角 + 辺の中央）をドラッグしてサイズを変更できます。</p><h3 id="削除" tabindex="-1">削除 <a class="header-anchor" href="#削除" aria-label="Permalink to &quot;削除&quot;">​</a></h3><ul><li>選択中にツールバーの「削除」ボタン</li><li>右クリックメニューから「削除」</li></ul><hr><h2 id="作成モード" tabindex="-1">作成モード <a class="header-anchor" href="#作成モード" aria-label="Permalink to &quot;作成モード&quot;">​</a></h2><p>AI が検出しなかった入力項目を手動で追加する機能です。</p><h3 id="操作手順" tabindex="-1">操作手順 <a class="header-anchor" href="#操作手順" aria-label="Permalink to &quot;操作手順&quot;">​</a></h3><ol><li>ツールバーの「作成」ボタンまたは <code>N</code> キーで作成モードに切替</li><li>カーソルが十字（crosshair）に変わります</li><li>プレビュー上でドラッグして矩形を描画</li></ol><p><img src="'+c+'" alt="作成モードドラッグ"></p><ol start="4"><li>マウスを離すとポップオーバーが表示されます</li></ol><p><img src="'+h+'" alt="作成ポップオーバー"></p><h3 id="ai-推論" tabindex="-1">AI 推論 <a class="header-anchor" href="#ai-推論" aria-label="Permalink to &quot;AI 推論&quot;">​</a></h3><p>描画した矩形内のセル情報を AI が自動分析し、以下を推論します:</p><ul><li><strong>名前</strong>: クラスター名（周辺ラベルから推測）</li><li><strong>タイプ</strong>: 入力項目の種類（テキスト、数値、日付など）</li></ul><p>推論結果はポップオーバーに自動入力されますが、自由に編集できます。</p><h3 id="確認と作成" tabindex="-1">確認と作成 <a class="header-anchor" href="#確認と作成" aria-label="Permalink to &quot;確認と作成&quot;">​</a></h3><ul><li>名前・タイプを確認/編集して「作成」ボタンをクリック</li><li>作成後は自動的に選択状態になります</li><li><strong>作成モードは維持されます</strong> — 続けて次のクラスターを描画できます</li></ul><div class="tip custom-block"><p class="custom-block-title">AI をスキップ</p><p>AI 推論を待たずに「スキップして手動作成」リンクで即座に手動入力に切り替えられます。</p></div><hr><h2 id="ズーム操作" tabindex="-1">ズーム操作 <a class="header-anchor" href="#ズーム操作" aria-label="Permalink to &quot;ズーム操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td>ズームイン</td><td>ツールバーの虫眼鏡(+)ボタン</td></tr><tr><td>ズームアウト</td><td>ツールバーの虫眼鏡(-)ボタン</td></tr><tr><td>ズームリセット</td><td>パーセンテージ表示をクリック</td></tr><tr><td>マウスホイール</td><td><code>Ctrl</code>/<code>Cmd</code> + スクロール</td></tr></tbody></table><p>ズーム範囲: 50% 〜 300%</p><hr><h2 id="プロパティパネル" tabindex="-1">プロパティパネル <a class="header-anchor" href="#プロパティパネル" aria-label="Permalink to &quot;プロパティパネル&quot;">​</a></h2><p>クラスターを選択すると、右側のプロパティパネルに以下の情報が表示・編集できます:</p><ul><li><strong>セルアドレス</strong>: Excel 上の位置 (例: C5)</li><li><strong>信頼度</strong>: AI の推測確度</li><li><strong>名前</strong>: クラスター名</li><li><strong>タイプ</strong>: 入力項目の種類</li><li><strong>読み取り専用</strong>: トグル</li><li><strong>パラメータ</strong>: 入力パラメータ (key=value 形式)</li></ul><hr><h2 id="キーボードショートカット一覧" tabindex="-1">キーボードショートカット一覧 <a class="header-anchor" href="#キーボードショートカット一覧" aria-label="Permalink to &quot;キーボードショートカット一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>キー</th><th>操作</th></tr></thead><tbody><tr><td><code>V</code></td><td>選択モードに切替</td></tr><tr><td><code>N</code></td><td>作成モードに切替</td></tr><tr><td><code>Esc</code></td><td>選択モードに戻る / 操作キャンセル</td></tr><tr><td><code>↑</code> <code>↓</code> <code>←</code> <code>→</code></td><td>選択クラスターを 1px 移動</td></tr><tr><td><code>Shift</code> + 矢印</td><td>選択クラスターを 10px 移動</td></tr><tr><td><code>Ctrl</code>/<code>Cmd</code> + スクロール</td><td>ズーム</td></tr><tr><td><code>Shift</code> + クリック</td><td>複数選択に追加/除外</td></tr><tr><td><code>Ctrl</code>/<code>Cmd</code> + クリック</td><td>複数選択に追加/除外</td></tr></tbody></table>',52)])])}const x=e(s,[["render",n]]);export{f as __pageData,x as default};
